SELECT DISTINCT i.country, i.city
FROM user_sessions us
JOIN ip_addresses i ON us.ip_address_id = i.ip_address_id;

SELECT 
  CAST(
    (SELECT COUNT(DISTINCT user_id)
     FROM user_sessions
     WHERE device_type = 'mobile'
    ) AS REAL
  ) /
  (SELECT COUNT(DISTINCT user_id)
   FROM user_sessions
   WHERE device_type = 'desktop'
  ) AS ratio;

SELECT website_name, domain
FROM websites
WHERE website_status = 'active' AND country = 'USA';
